// worker-public.js
export default {
  async fetch(request, env, ctx) {
    try {
      const url = new URL(request.url);
      const path = url.pathname;

      if (request.method !== 'GET' && request.method !== 'POST') {
        return new Response('Method not allowed', { status: 405 });
      }

      const requestId = crypto.randomUUID();
      const clientIP = request.headers.get('CF-Connecting-IP') || 'unknown';
      
      const sanitizedHeaders = new Headers();
      const allowedHeaders = ['content-type', 'accept', 'user-agent'];
      for (const [key, value] of request.headers.entries()) {
        if (allowedHeaders.includes(key.toLowerCase())) {
          sanitizedHeaders.set(key, value);
        }
      }
      sanitizedHeaders.set('X-Request-ID', requestId);
      sanitizedHeaders.set('X-Client-IP', clientIP);
      sanitizedHeaders.set('X-Forwarded-By', 'public-worker');

      let body = null;
      if (request.method === 'POST') {
        const contentType = request.headers.get('content-type') || '';
        if (contentType.includes('application/json')) {
          try {
            const text = await request.text();
            if (text.length > 1048576) {
              return new Response(JSON.stringify({ error: 'Payload too large' }), {
                status: 413,
                headers: { 'Content-Type': 'application/json' }
              });
            }
            body = text;
            JSON.parse(body);
          } catch (e) {
            return new Response(JSON.stringify({ error: 'Invalid JSON' }), {
              status: 400,
              headers: { 'Content-Type': 'application/json' }
            });
          }
        } else {
          return new Response(JSON.stringify({ error: 'Unsupported content type' }), {
            status: 415,
            headers: { 'Content-Type': 'application/json' }
          });
        }
      }

      let response;
      
      if (path.startsWith('/api/auth')) {
        if (!env.AUTH_SERVICE) {
          return new Response(JSON.stringify({ error: 'Service unavailable' }), {
            status: 503,
            headers: { 'Content-Type': 'application/json' }
          });
        }
        
        const authRequest = new Request(request.url, {
          method: request.method,
          headers: sanitizedHeaders,
          body: body
        });
        
        response = await env.AUTH_SERVICE.fetch(authRequest);
        
      } else if (path.startsWith('/api/data')) {
        if (!env.DATA_SERVICE) {
          return new Response(JSON.stringify({ error: 'Service unavailable' }), {
            status: 503,
            headers: { 'Content-Type': 'application/json' }
          });
        }
        
        const dataRequest = new Request(request.url, {
          method: request.method,
          headers: sanitizedHeaders,
          body: body
        });
        
        response = await env.DATA_SERVICE.fetch(dataRequest);
        
      } else if (path.startsWith('/api/process')) {
        if (!env.PROCESSING_SERVICE) {
          return new Response(JSON.stringify({ error: 'Service unavailable' }), {
            status: 503,
            headers: { 'Content-Type': 'application/json' }
          });
        }
        
        const processRequest = new Request(request.url, {
          method: request.method,
          headers: sanitizedHeaders,
          body: body
        });
        
        response = await env.PROCESSING_SERVICE.fetch(processRequest);
        
      } else {
        return new Response(JSON.stringify({ 
          error: 'Not found',
          availableEndpoints: ['/api/auth', '/api/data', '/api/process']
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const responseHeaders = new Headers(response.headers);
      responseHeaders.set('X-Request-ID', requestId);
      responseHeaders.delete('X-Internal-Token');
      responseHeaders.set('X-Content-Type-Options', 'nosniff');
      responseHeaders.set('X-Frame-Options', 'DENY');
      responseHeaders.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');

      return new Response(response.body, {
        status: response.status,
        statusText: response.statusText,
        headers: responseHeaders
      });

    } catch (error) {
      console.error('Public worker error:', error);
      return new Response(JSON.stringify({ 
        error: 'Internal server error',
        requestId: crypto.randomUUID()
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

