export default {
  async fetch(request, env, ctx) {
    try {
      const forwardedBy = request.headers.get('X-Forwarded-By');
      if (!forwardedBy) {
        return new Response(JSON.stringify({ error: 'Direct access not allowed' }), {
          status: 403,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const url = new URL(request.url);
      const path = url.pathname;
      const requestId = request.headers.get('X-Request-ID') || crypto.randomUUID();

      if (path === '/api/auth/login' && request.method === 'POST') {
        const body = await request.json();
        
        if (!body.username || !body.password) {
          return new Response(JSON.stringify({ error: 'Missing credentials' }), {
            status: 400,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        if (typeof body.username !== 'string' || typeof body.password !== 'string') {
          return new Response(JSON.stringify({ error: 'Invalid credentials format' }), {
            status: 400,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        if (body.username.length > 100 || body.password.length > 100) {
          return new Response(JSON.stringify({ error: 'Credentials too long' }), {
            status: 400,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        const encoder = new TextEncoder();
        const data = encoder.encode(body.password);
        const hashBuffer = await crypto.subtle.digest('SHA-256', data);
        const hashArray = Array.from(new Uint8Array(hashBuffer));
        const passwordHash = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');

        const validUsername = 'testuser';
        const validPasswordHash = 'a665a45920422f9d417e4867efdc4fb8a04a1f3fff1fa07e998e86f7f7a27ae3';

        if (body.username === validUsername && passwordHash === validPasswordHash) {
          const token = await generateToken(body.username);
          
          return new Response(JSON.stringify({ 
            success: true,
            token: token,
            username: body.username
          }), {
            status: 200,
            headers: { 
              'Content-Type': 'application/json',
              'X-Request-ID': requestId
            }
          });
        } else {
          return new Response(JSON.stringify({ error: 'Invalid credentials' }), {
            status: 401,
            headers: { 'Content-Type': 'application/json' }
          });
        }

      } else if (path === '/api/auth/verify' && request.method === 'POST') {
        const body = await request.json();
        
        if (!body.token) {
          return new Response(JSON.stringify({ error: 'Missing token' }), {
            status: 400,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        const isValid = await verifyToken(body.token);
        
        if (isValid) {
          return new Response(JSON.stringify({ 
            valid: true,
            username: isValid.username
          }), {
            status: 200,
            headers: { 
              'Content-Type': 'application/json',
              'X-Request-ID': requestId
            }
          });
        } else {
          return new Response(JSON.stringify({ valid: false }), {
            status: 401,
            headers: { 'Content-Type': 'application/json' }
          });
        }

      } else {
        return new Response(JSON.stringify({ error: 'Not found' }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

    } catch (error) {
      console.error('Auth worker error:', error);
      return new Response(JSON.stringify({ error: 'Internal server error' }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

async function generateToken(username) {
  const payload = {
    username: username,
    issued: Date.now(),
    expires: Date.now() + 3600000
  };
  
  const encoder = new TextEncoder();
  const data = encoder.encode(JSON.stringify(payload));
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  const signature = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
  
  const token = btoa(JSON.stringify(payload)) + '.' + signature;
  return token;
}

async function verifyToken(token) {
  try {
    const parts = token.split('.');
    if (parts.length !== 2) return false;
    
    const payload = JSON.parse(atob(parts[0]));
    const signature = parts[1];
    
    if (payload.expires < Date.now()) return false;
    
    const encoder = new TextEncoder();
    const data = encoder.encode(JSON.stringify(payload));
    const hashBuffer = await crypto.subtle.digest('SHA-256', data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    const expectedSignature = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    
    if (signature !== expectedSignature) return false;
    
    return payload;
  } catch (e) {
    return false;
  }
}

